const MAIN_ALPHADOG_UI_VERSION = "v1.0.04 - UI Recovery Static Controls";
const LOGO_PNG_BASE64 = "";
const INDEX_HTML = "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1,viewport-fit=cover\">\n  <title>AlphaDog v1.0</title>\n  <link rel=\"icon\" type=\"image/png\" href=\"/main_alphadog_favicon.png\">\n  <link rel=\"apple-touch-icon\" href=\"/main_alphadog_apple_touch_icon.png\">\n  <meta name=\"apple-mobile-web-app-capable\" content=\"yes\">\n  <meta name=\"apple-mobile-web-app-title\" content=\"AlphaDog\">\n  <meta name=\"theme-color\" content=\"#080f21\">\n  <style>\n    :root{--bg:#080f21;--panel:#111a30;--panel2:#0d1428;--line:#26365f;--text:#f3f7ff;--muted:#aebbd2;--blue:#2477ff;--blue2:#135de0;--green:#65e6a3;--red:#ff6b6b;--yellow:#ffd36e;--shadow:0 18px 40px rgba(0,0,0,.35)}\n    *{box-sizing:border-box} body{margin:0;background:radial-gradient(circle at top,#151f39 0,#080f21 38%,#050913 100%);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Arial,sans-serif;min-height:100vh}.wrap{max-width:1160px;margin:0 auto;padding:18px 14px 42px}.hero{display:flex;align-items:center;justify-content:space-between;gap:12px;margin:4px 0 18px}.brand{display:flex;align-items:center;gap:14px}.logo{width:72px;height:72px;border-radius:50%;background:#fff;padding:4px;box-shadow:var(--shadow)}h1{font-size:38px;line-height:1;margin:0;font-weight:900;letter-spacing:-.04em}.v{font-size:16px;color:var(--muted);font-weight:800;margin-top:5px}.adminBtn,.backBtn{border:1px solid #385083;background:#141f3a;border-radius:15px;color:#fff;font-weight:900;padding:12px 16px;font-size:15px;cursor:pointer}.primary{border:0;border-radius:15px;background:linear-gradient(180deg,var(--blue),var(--blue2));color:#fff;font-weight:900;padding:12px 16px;font-size:15px;box-shadow:0 10px 22px rgba(36,119,255,.22);cursor:pointer}.panel{background:rgba(17,26,48,.92);border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow);padding:16px;margin-bottom:14px}.filterTitle{font-size:14px;color:var(--muted);font-weight:800;text-transform:uppercase;letter-spacing:.08em;margin:0 0 10px}.chips{display:flex;gap:9px;flex-wrap:wrap}.chip{display:inline-flex;align-items:center;gap:7px;border:1px solid var(--line);background:#141f3a;border-radius:999px;padding:10px 12px;font-weight:800;color:#dfe8fb;user-select:none;cursor:pointer}.chip input{accent-color:var(--blue);width:18px;height:18px}.controls{display:grid;grid-template-columns:1fr;gap:14px}select,input.pin{appearance:none;background:#141f3a;color:var(--text);border:1px solid var(--line);border-radius:16px;padding:14px 16px;font-size:17px;font-weight:850;width:100%}.bar{display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap;margin:12px 2px 14px}.status{color:var(--muted);font-size:14px;font-weight:750}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:13px}.card{position:relative;overflow:hidden;background:linear-gradient(180deg,#141e36,#0c1428);border:1px solid #2b3a65;border-radius:22px;padding:14px;min-height:222px;box-shadow:var(--shadow)}.card:before{content:\"\";position:absolute;inset:0;background:radial-gradient(circle at 90% 15%,rgba(36,119,255,.18),transparent 35%);pointer-events:none}.top{position:relative;display:flex;justify-content:space-between;gap:8px;align-items:flex-start}.player{font-size:20px;line-height:1.06;font-weight:950;letter-spacing:-.03em}.badge{flex:0 0 auto;border-radius:999px;padding:6px 8px;font-weight:950;font-size:11px;border:1px solid #3b4c7d;background:#101a31;text-transform:uppercase}.goblin{color:var(--green)}.demon{color:#ff7676}.regular{color:#dce7ff}.teams{position:relative;color:var(--muted);font-size:13px;font-weight:800;margin-top:8px;line-height:1.35}.date{position:relative;margin-top:9px;color:#c8d5ec;font-size:13px;font-weight:750}.lineBox{position:relative;margin-top:12px;display:inline-flex;gap:6px;align-items:center;border:1px solid #334573;background:#0b1326;border-radius:14px;padding:8px 10px;font-weight:950;font-size:13px}.side{color:#fff}.score{position:absolute;right:14px;bottom:12px;text-align:right}.scoreNum{font-size:34px;font-weight:1000;letter-spacing:-.05em}.scoreLbl{color:var(--muted);font-size:11px;font-weight:900;text-transform:uppercase}.comment{position:relative;margin-top:12px;color:#b9c7dc;font-size:12px;line-height:1.32;max-width:72%;font-weight:700}.empty{text-align:center;color:var(--muted);padding:44px 20px;border:1px dashed var(--line);border-radius:22px;background:#10182d}.err{color:#ff8b8b}.good{color:var(--green)}.bad{color:var(--red)}.warn{color:var(--yellow)}.hidden{display:none!important}.adminGrid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:13px}.dataCard{background:linear-gradient(180deg,#141e36,#0c1428);border:1px solid #2b3a65;border-radius:22px;padding:15px;box-shadow:var(--shadow);min-height:174px}.dataTop{display:flex;justify-content:space-between;gap:10px;align-items:flex-start}.dataTitle{font-size:20px;font-weight:950}.freq{font-size:12px;color:var(--muted);font-weight:900;text-transform:uppercase}.check{font-size:22px;font-weight:1000}.metric{margin-top:10px;color:#c9d6ec;font-size:13px;line-height:1.4;font-weight:750}.quality{font-size:30px;font-weight:1000;margin-top:8px}.small{font-size:12px;color:var(--muted);line-height:1.35}.modal{position:fixed;inset:0;background:rgba(0,0,0,.62);display:flex;align-items:center;justify-content:center;padding:18px;z-index:10}.modalBox{background:#111a30;border:1px solid var(--line);border-radius:24px;box-shadow:var(--shadow);padding:18px;max-width:380px;width:100%}.modalBox h2{margin:0 0 10px}.modalActions{display:flex;gap:10px;margin-top:12px}.modalActions button{flex:1}.jsError{background:#331525;border:1px solid #7f3150;color:#ffd5e0;border-radius:14px;padding:10px;margin:10px 0;font-weight:800}\n    @media(max-width:650px){.wrap{padding:14px 10px 36px}.hero{align-items:flex-start}.brand{gap:10px}.logo{width:58px;height:58px}h1{font-size:32px}.panel{border-radius:21px;padding:13px}.grid,.adminGrid{grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.card{border-radius:19px;padding:11px;min-height:222px}.player,.dataTitle{font-size:17px}.teams,.date{font-size:12px}.lineBox{font-size:12px;padding:7px 8px}.scoreNum{font-size:30px}.comment{font-size:11px;max-width:68%}.chip{padding:9px 10px;font-size:14px}.adminBtn,.primary,.backBtn{padding:10px 12px}}\n  </style>\n</head>\n<body>\n<main class=\"wrap\">\n  <header class=\"hero\">\n    <div class=\"brand\"><img class=\"logo\" src=\"/main_alphadog_logo.png\" alt=\"AlphaDog logo\"><div><h1>AlphaDog</h1><div class=\"v\">v1.0</div></div></div>\n    <button class=\"adminBtn\" type=\"button\" id=\"adminOpen\">Admin</button>\n  </header>\n  <section id=\"boardScreen\">\n    <section class=\"panel controls\">\n      <div><p class=\"filterTitle\">Prop lines</p><div class=\"chips\" id=\"propFilters\">\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"props\" data-value=\"TOTAL_BASES\">Total Bases</label>\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"props\" data-value=\"RBI\">RBI</label>\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"props\" data-value=\"HITS\">Hits</label>\n      </div></div>\n      <div><p class=\"filterTitle\">Line type</p><div class=\"chips\" id=\"typeFilters\">\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"types\" data-value=\"goblin\">Goblin</label>\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"types\" data-value=\"demon\">Demon</label>\n        <label class=\"chip\"><input type=\"checkbox\" checked data-set=\"types\" data-value=\"regular\">Regular</label>\n      </div></div>\n      <div><p class=\"filterTitle\">Final score</p><select id=\"scoreFilter\"><option value=\"90\">90+</option><option value=\"85\">85+</option><option value=\"80\">80+</option><option value=\"75\">75+</option><option value=\"70\" selected>70+</option><option value=\"60\">60+</option></select></div>\n    </section>\n    <div class=\"bar\"><div class=\"status\" id=\"status\">Starting UI...</div><button class=\"primary\" type=\"button\" id=\"refresh\">Refresh</button></div>\n    <section class=\"grid\" id=\"cards\"></section>\n  </section>\n  <section id=\"adminScreen\" class=\"hidden\">\n    <div class=\"bar\"><button class=\"backBtn\" type=\"button\" id=\"backBoard\">\u2190 Board</button><button class=\"primary\" type=\"button\" id=\"fullRefresh\">Refresh Full Data</button></div>\n    <div class=\"panel\"><div class=\"status\" id=\"adminStatus\">Loading freshness...</div><div class=\"small\">Sleeper stays manual. Full refresh does not run static data.</div></div>\n    <section class=\"adminGrid\" id=\"adminCards\"></section>\n  </section>\n</main>\n<div class=\"modal hidden\" id=\"pinModal\"><div class=\"modalBox\"><h2>Admin PIN</h2><p class=\"small\">Enter PIN to open the data console.</p><input class=\"pin\" id=\"pinInput\" inputmode=\"numeric\" type=\"password\" placeholder=\"PIN\"><div class=\"modalActions\"><button class=\"backBtn\" type=\"button\" id=\"pinCancel\">Cancel</button><button class=\"primary\" type=\"button\" id=\"pinGo\">Open</button></div><p class=\"err\" id=\"pinErr\"></p></div></div>\n<script>\n(function(){\n'use strict';\nconst UI_VERSION='v1.0.04 - UI Recovery Static Controls';\nconst TEAM={ARI:'Arizona Diamondbacks',ATL:'Atlanta Braves',BAL:'Baltimore Orioles',BOS:'Boston Red Sox',CHC:'Chicago Cubs',CWS:'Chicago White Sox',CHW:'Chicago White Sox',CIN:'Cincinnati Reds',CLE:'Cleveland Guardians',COL:'Colorado Rockies',DET:'Detroit Tigers',HOU:'Houston Astros',KC:'Kansas City Royals',KCR:'Kansas City Royals',LAA:'Los Angeles Angels',LAD:'Los Angeles Dodgers',MIA:'Miami Marlins',MIL:'Milwaukee Brewers',MIN:'Minnesota Twins',NYM:'New York Mets',NYY:'New York Yankees',ATH:'Athletics',OAK:'Athletics',PHI:'Philadelphia Phillies',PIT:'Pittsburgh Pirates',SD:'San Diego Padres',SDP:'San Diego Padres',SEA:'Seattle Mariners',SF:'San Francisco Giants',SFG:'San Francisco Giants',STL:'St. Louis Cardinals',TB:'Tampa Bay Rays',TBR:'Tampa Bay Rays',TEX:'Texas Rangers',TOR:'Toronto Blue Jays',WSH:'Washington Nationals',WAS:'Washington Nationals'};\nlet rows=[];\nlet filters={props:new Set(['HITS','RBI','TOTAL_BASES']),types:new Set(['goblin','demon','regular']),score:70};\nconst $=id=>document.getElementById(id);\nfunction esc(v){return String(v??'').replace(/[&<>\"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;'}[c]))}\nfunction team(v){return TEAM[v]||v||'Unknown Team'}\nfunction propLabel(p){return p==='TOTAL_BASES'?'Total Bases':p==='RBI'?'RBI':p==='HITS'?'Hits':String(p||'Prop')}\nfunction typeLabel(t){return t==='regular'?'Regular':String(t||'regular').charAt(0).toUpperCase()+String(t||'regular').slice(1)}\nfunction fmtDate(v,fallback){if(v){let d=new Date(v);if(!isNaN(d))return new Intl.DateTimeFormat(undefined,{weekday:'short',month:'short',day:'numeric',hour:'numeric',minute:'2-digit'}).format(d);if(String(v).trim())return String(v)}return fallback||'Game time unavailable'}\nfunction friendlyComment(r){const risks=(r.risks||[]).concat((r.risk_notes_parsed&&r.risk_notes_parsed.risks)||[]);const mods=Array.isArray(r.derived_modifiers)?r.derived_modifiers:[];const score=Number(r.final_score||0);const noVig=Number(r.no_vig_prob||0);const market=Number(r.market_confidence||0);const pos=mods.filter(m=>Number(m.value)>0.75).sort((a,b)=>Number(b.value)-Number(a.value));const neg=mods.filter(m=>Number(m.value)<-0.75).sort((a,b)=>Number(a.value)-Number(b.value));if(r.candidate_status==='DEFERRED_UNPICKABLE'||risks.includes('pickability_gate_failed'))return 'Good raw profile, but this side is not confirmed pickable on the current board.';if(pos[0]){let id=String(pos[0].id||'');if(id.includes('LINEUP'))return 'Lineup slot is giving this leg extra support.';if(id.includes('GAME_TOTAL'))return 'Run environment is helping this leg.';if(id.includes('PARK'))return 'Ballpark context is helping this matchup.';if(id.includes('MARKET'))return 'Market depth is supporting the read.';}if(neg[0]){let id=String(neg[0].id||'');if(id.includes('PARK'))return 'Useful lean, but park context is working against it.';if(id.includes('GAME_TOTAL'))return 'Playable profile, but run environment is not ideal.';return 'Useful lean, but one context factor is dragging it down.';}if(risks.includes('under_cap'))return 'Under side has support, but AlphaDog is keeping it capped.';if(risks.includes('thin_under_3_books')||Number(r.book_count||0)<3)return 'Positive read, but sportsbook coverage is still thin.';if(score>=80)return 'Strong all-around AlphaDog profile.';if(noVig>=0.62&&market>=0.4)return 'Market lean and confidence are both pointing the same way.';if(noVig>=0.58)return 'Market lean is positive, but still not elite.';return 'Monitor only. Edge is modest.'}\nfunction normalizeType(r){let t=String(r.board_line_type||r.line_type||'regular').toLowerCase();if(t==='standard'||t==='alt')t='regular';return ['goblin','demon','regular'].includes(t)?t:'regular'}\nfunction bindFilters(){document.querySelectorAll('input[type=checkbox][data-set]').forEach(el=>{const set=filters[el.dataset.set];if(set){el.checked=set.has(el.dataset.value);el.addEventListener('change',()=>{el.checked?set.add(el.dataset.value):set.delete(el.dataset.value);render();});}});$('scoreFilter').value=String(filters.score);$('scoreFilter').addEventListener('change',e=>{filters.score=Number(e.target.value);render();});}\nfunction render(){let shown=rows.filter(r=>filters.props.has(r.prop_family)&&filters.types.has(normalizeType(r))&&Number(r.final_score||0)>=filters.score);$('status').textContent=shown.length+' shown / '+rows.length+' loaded \u2022 '+UI_VERSION;if(!shown.length){$('cards').innerHTML='<div class=\"empty\" style=\"grid-column:1/-1\">No legs match these filters.</div>';return}$('cards').innerHTML=shown.map(r=>{let t=normalizeType(r);let score=Number(r.final_score||0);return '<article class=\"card\"><div class=\"top\"><div class=\"player\">'+esc(r.player_name)+'</div><div class=\"badge '+t+'\">'+typeLabel(t)+'</div></div><div class=\"teams\">'+esc(team(r.team))+'<br>vs '+esc(team(r.opponent))+'</div><div class=\"date\">'+esc(fmtDate(r.game_datetime_utc||r.start_time,r.game_time_label))+'</div><div class=\"lineBox\"><span>'+esc(propLabel(r.prop_family))+'</span><span class=\"side\">'+esc(r.line_direction)+'</span><span>'+esc(r.line_number)+'</span></div><div class=\"comment\">'+esc(friendlyComment(r))+'</div><div class=\"score\"><div class=\"scoreLbl\">Score</div><div class=\"scoreNum\">'+score.toFixed(1)+'</div></div></article>'}).join('')}\nasync function load(){try{$('status').textContent='Loading board...';$('cards').innerHTML='';let r=await fetch('/main_alphadog_board?score_min=0&t='+Date.now(),{cache:'no-store'});let j=await r.json();if(!j.ok)throw Error(j.error||'Board load failed');rows=Array.isArray(j.rows)?j.rows:[];render()}catch(e){$('status').innerHTML='<span class=\"err\">Board load failed: '+esc(e.message||e)+'</span>';$('cards').innerHTML='<div class=\"empty err\" style=\"grid-column:1/-1\">Could not load board. Check DB binding and /main_alphadog_health.</div>'}}\nfunction showAdmin(){document.body.scrollTop=0;document.documentElement.scrollTop=0;$('boardScreen').classList.add('hidden');$('adminScreen').classList.remove('hidden');loadAdmin()}function showBoard(){$('adminScreen').classList.add('hidden');$('boardScreen').classList.remove('hidden')}function openPin(){$('pinModal').classList.remove('hidden');$('pinInput').value='';$('pinErr').textContent='';setTimeout(()=>$('pinInput').focus(),50)}function closePin(){$('pinModal').classList.add('hidden')}function unlock(){if($('pinInput').value==='3971'){closePin();showAdmin()}else $('pinErr').textContent='Wrong PIN.'}\nfunction statusIcon(ok){return ok?'<span class=\"check good\">\u2713</span>':'<span class=\"check bad\">\u00d7</span>'}function fmt(v){if(!v)return 'Not found';let d=new Date(String(v).replace(' ','T')+'Z');if(!isNaN(d))return new Intl.DateTimeFormat(undefined,{month:'short',day:'numeric',hour:'numeric',minute:'2-digit'}).format(d);return String(v)}function adminCard(c){let cls=c.quality_score>=90?'good':c.quality_score>=75?'warn':'bad';return '<article class=\"dataCard\"><div class=\"dataTop\"><div><div class=\"dataTitle\">'+esc(c.title)+'</div><div class=\"freq\">'+esc(c.frequency)+'</div></div>'+statusIcon(c.ok)+'</div><div class=\"metric\">Last Update: '+esc(fmt(c.last_update))+'</div><div class=\"quality '+cls+'\">'+esc(c.quality_score)+'/100</div><div class=\"small\">Data Quality: '+esc(c.quality_note||'')+'</div><div class=\"metric\">Next Update: '+esc(c.next_update||'By schedule')+'</div></article>'}\nasync function loadAdmin(){try{$('adminStatus').textContent='Loading freshness...';let r=await fetch('/main_alphadog_admin_status?t='+Date.now(),{cache:'no-store'});let j=await r.json();if(!j.ok)throw Error(j.error||'Admin status failed');$('adminStatus').textContent='Freshness loaded \u2022 '+j.version;$('adminCards').innerHTML=(j.cards||[]).map(adminCard).join('')}catch(e){$('adminStatus').innerHTML='<span class=\"err\">Admin load failed: '+esc(e.message||e)+'</span>'}}\nasync function startFullRefresh(){try{let ok=confirm('Start full data refresh now? You can close the browser after it starts.');if(!ok)return;$('adminStatus').textContent='Starting full refresh...';let r=await fetch('/main_alphadog_admin_refresh',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({pin:'3971'}),cache:'no-store'});let j=await r.json();if(!j.ok)throw Error(j.error||'Refresh start failed');alert('Data Refresh Started\\nEstimated time: '+(j.estimated_minutes||'8-15')+' minutes\\nJob ID: '+(j.refresh_id||j.task_id||'created'));loadAdmin()}catch(e){alert('Refresh failed to start: '+(e.message||e));loadAdmin()}}\nfunction boot(){try{bindFilters();$('refresh').addEventListener('click',load);$('adminOpen').addEventListener('click',openPin);$('pinCancel').addEventListener('click',closePin);$('pinGo').addEventListener('click',unlock);$('pinInput').addEventListener('keydown',e=>{if(e.key==='Enter')unlock()});$('backBoard').addEventListener('click',showBoard);$('fullRefresh').addEventListener('click',startFullRefresh);load();}catch(e){$('status').innerHTML='<div class=\"jsError\">UI boot error: '+esc(e.message||e)+'</div>';}}\nif(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();\n})();\n</script>\n</body>\n</html>";
const TEAM_NAMES = {ARI:"Arizona Diamondbacks",ATL:"Atlanta Braves",BAL:"Baltimore Orioles",BOS:"Boston Red Sox",CHC:"Chicago Cubs",CWS:"Chicago White Sox",CHW:"Chicago White Sox",CIN:"Cincinnati Reds",CLE:"Cleveland Guardians",COL:"Colorado Rockies",DET:"Detroit Tigers",HOU:"Houston Astros",KC:"Kansas City Royals",KCR:"Kansas City Royals",LAA:"Los Angeles Angels",LAD:"Los Angeles Dodgers",MIA:"Miami Marlins",MIL:"Milwaukee Brewers",MIN:"Minnesota Twins",NYM:"New York Mets",NYY:"New York Yankees",ATH:"Athletics",OAK:"Athletics",PHI:"Philadelphia Phillies",PIT:"Pittsburgh Pirates",SD:"San Diego Padres",SDP:"San Diego Padres",SEA:"Seattle Mariners",SF:"San Francisco Giants",SFG:"San Francisco Giants",STL:"St. Louis Cardinals",TB:"Tampa Bay Rays",TBR:"Tampa Bay Rays",TEX:"Texas Rangers",TOR:"Toronto Blue Jays",WSH:"Washington Nationals",WAS:"Washington Nationals"};
function jsonResponse(data,status=200){return new Response(JSON.stringify(data,null,2),{status,headers:{"content-type":"application/json; charset=utf-8","cache-control":"no-store","access-control-allow-origin":"*"}})}
function htmlResponse(data,status=200){return new Response(data,{status,headers:{"content-type":"text/html; charset=utf-8","cache-control":"no-store"}})}
function textResponse(data,status=200){return new Response(data,{status,headers:{"content-type":"text/plain; charset=utf-8","cache-control":"no-store"}})}
function pngResponse(){const bin=atob(LOGO_PNG_BASE64);const bytes=new Uint8Array(bin.length);for(let i=0;i<bin.length;i++)bytes[i]=bin.charCodeAt(i);return new Response(bytes,{headers:{"content-type":"image/png","cache-control":"public, max-age=86400"}})}
function safeJsonParse(value,fallback={}){try{return value?JSON.parse(value):fallback}catch{return fallback}}
function normalizeKey(value){return String(value||"").toLowerCase().replace(/[^a-z0-9]/g,"")}
function normalizePropFamily(value){const v=String(value||"").toUpperCase();if(v==="TOTAL BASES"||v==="TB"||v==="TOTAL_BASES")return"TOTAL_BASES";if(v==="RBIS"||v==="RBI")return"RBI";if(v==="HIT"||v==="HITS")return"HITS";return v}
function propToPrizePicksStat(prop){if(prop==="TOTAL_BASES")return"Total Bases";if(prop==="RBI")return"RBIs";if(prop==="HITS")return"Hits";return prop}
function propToOddsMarket(prop){if(prop==="TOTAL_BASES")return"batter_total_bases";if(prop==="RBI")return"batter_rbis";if(prop==="HITS")return"batter_hits";return""}
function normalizeOddsType(row,risk){const gate=risk?.pickability_gate||{};const fromGate=String(gate.matched_odds_type||"").toLowerCase();if(["goblin","demon","standard","regular"].includes(fromGate))return fromGate==="standard"?"regular":fromGate;const fromRow=String(row.line_type||"").toLowerCase();if(["goblin","demon","regular"].includes(fromRow))return fromRow;return"regular"}
function formatPtLabel(slateDate,pt){if(!pt)return null;const clean=String(pt).trim();const m=clean.match(/^(\d{1,2}):(\d{2})$/);let timeText=clean;if(m){const h=Number(m[1]);const mm=m[2];const hour12=((h+11)%12)+1;const ampm=h>=12?"PM":"AM";timeText=`${hour12}:${mm} ${ampm} PT`}try{const d=new Date(`${slateDate}T12:00:00Z`);const day=new Intl.DateTimeFormat("en-US",{weekday:"short",month:"short",day:"numeric"}).format(d);return `${day}, ${timeText}`}catch{return `${slateDate} ${timeText}`}}
async function chooseSlate(db,requestedSlate){if(requestedSlate)return requestedSlate;const row=await db.prepare(`SELECT slate_date FROM active_score_board WHERE COALESCE(slate_date,'')<>'' GROUP BY slate_date ORDER BY slate_date DESC LIMIT 1`).first().catch(()=>null);if(row?.slate_date)return row.slate_date;const fallback=await db.prepare(`SELECT slate_date FROM score_candidate_board WHERE COALESCE(slate_date,'')<>'' GROUP BY slate_date ORDER BY slate_date DESC LIMIT 1`).first().catch(()=>null);return fallback?.slate_date||null}
async function loadPrizePicksMatch(db,row,risk,activeSlate){const gate=risk?.pickability_gate||{};const lineId=gate.matched_line_id;if(lineId){const byId=await db.prepare(`SELECT line_id,player_name,team,opponent,stat_type,line_score,odds_type,start_time,slate_date,status FROM prizepicks_current_market_context WHERE line_id=? LIMIT 1`).bind(String(lineId)).first().catch(()=>null);if(byId)return byId}const statType=propToPrizePicksStat(row.prop_family);const normalized=normalizeKey(row.normalized_player_name||row.player_name);if(!normalized)return null;return await db.prepare(`SELECT line_id,player_name,team,opponent,stat_type,line_score,odds_type,start_time,slate_date,status FROM prizepicks_current_market_context WHERE status='ACTIVE' AND slate_date=? AND lower(replace(replace(replace(player_name,' ',''),'.',''),'''',''))=? AND stat_type=? AND ABS(COALESCE(line_score,-999)-?)<0.001 ORDER BY board_updated_at DESC LIMIT 1`).bind(activeSlate,normalized,statType,Number(row.line_number||0)).first().catch(()=>null)}
async function loadOddsApiMatch(db,row,activeSlate){const market=propToOddsMarket(row.prop_family);if(!market)return null;const normalized=normalizeKey(row.normalized_player_name||row.player_name);const side=String(row.line_direction||"").toLowerCase();return await db.prepare(`SELECT event_id,player_name,home_team,away_team,commence_time_pt,window_bucket,bookmaker_key,market_key,outcome_name,outcome_point,updated_at FROM odds_api_player_props WHERE slate_date=? AND market_key=? AND lower(replace(replace(replace(player_name,' ',''),'.',''),'''',''))=? AND lower(outcome_name)=? AND ABS(COALESCE(outcome_point,-999)-?)<0.001 ORDER BY updated_at DESC LIMIT 1`).bind(activeSlate,market,normalized,side,Number(row.line_number||0)).first().catch(()=>null)}
function parseAudit(row){const audit=safeJsonParse(row.audit_payload,{});const risk=safeJsonParse(row.risk_notes,{});return{derived_modifiers:Array.isArray(audit.derived_modifiers)?audit.derived_modifiers:[],book_count:audit.book_count??risk.book_count??null,base_score:audit.base_score??risk.base_score??null,derived_modifier_total:audit.derived_modifier_total??risk.derived_modifier_total??null}}
async function loadBoardRows(db,slateDate,scoreMin){const active=await db.prepare(`SELECT * FROM active_score_board WHERE slate_date=? AND final_score>=? AND prop_family IN ('HITS','RBI','TOTAL_BASES') ORDER BY final_score DESC LIMIT 2000`).bind(slateDate,scoreMin).all().catch(()=>null);if(active?.results?.length)return{source_table:"active_score_board",rows:active.results};const candidate=await db.prepare(`SELECT * FROM score_candidate_board WHERE slate_date=? AND final_score>=? AND prop_family IN ('HITS','RBI','TOTAL_BASES') ORDER BY final_score DESC LIMIT 2000`).bind(slateDate,scoreMin).all().catch(()=>null);return{source_table:"score_candidate_board",rows:candidate?.results||[]}}
async function board(request,env){if(!env.DB)return jsonResponse({ok:false,data_ok:false,version:MAIN_ALPHADOG_UI_VERSION,error:"Missing DB binding named DB"},500);const url=new URL(request.url);const requestedSlate=url.searchParams.get("slate_date")||"";const scoreMin=Number(url.searchParams.get("score_min")||0);const slateDate=await chooseSlate(env.DB,requestedSlate);if(!slateDate)return jsonResponse({ok:true,data_ok:false,version:MAIN_ALPHADOG_UI_VERSION,rows:[],error:"No board slate found"});const loaded=await loadBoardRows(env.DB,slateDate,scoreMin);const hydrated=[];for(const raw of loaded.rows){const row={...raw,prop_family:normalizePropFamily(raw.prop_family)};const risk=safeJsonParse(row.risk_notes,{});const auditInfo=parseAudit(row);const pp=await loadPrizePicksMatch(env.DB,row,risk,slateDate);const odds=pp?null:await loadOddsApiMatch(env.DB,row,slateDate);const oddsType=pp?.odds_type?String(pp.odds_type).toLowerCase():normalizeOddsType(row,risk);const teamValue=pp?.team||row.team||odds?.away_team||"";const oppValue=pp?.opponent||row.opponent||odds?.home_team||"";const gameTimeLabel=pp?.start_time?null:formatPtLabel(slateDate,odds?.commence_time_pt);hydrated.push({...row,team:TEAM_NAMES[teamValue]||teamValue||"",opponent:TEAM_NAMES[oppValue]||oppValue||"",team_abbrev:row.team||pp?.team||"",opponent_abbrev:row.opponent||pp?.opponent||"",line_type:oddsType==="standard"?"regular":oddsType,board_line_id:pp?.line_id||risk?.pickability_gate?.matched_line_id||null,board_status:pp?.status||null,board_slate_date:pp?.slate_date||null,start_time:pp?.start_time||null,game_datetime_utc:pp?.start_time||null,game_time_label:gameTimeLabel,odds_event_id:odds?.event_id||null,odds_bookmaker_key:odds?.bookmaker_key||null,risk_notes_parsed:risk,risks:Array.isArray(risk.risks)?risk.risks:[],caps:Array.isArray(risk.caps)?risk.caps:[],book_count:auditInfo.book_count,base_score:auditInfo.base_score,derived_modifier_total:auditInfo.derived_modifier_total,derived_modifiers:auditInfo.derived_modifiers})}const propCounts=hydrated.reduce((acc,r)=>{acc[r.prop_family]=(acc[r.prop_family]||0)+1;return acc},{});const typeCounts=hydrated.reduce((acc,r)=>{acc[r.line_type]=(acc[r.line_type]||0)+1;return acc},{});return jsonResponse({ok:true,data_ok:hydrated.length>0,version:MAIN_ALPHADOG_UI_VERSION,worker:"main_alphadog_worker",slate_date:slateDate,requested_slate_date:requestedSlate||slateDate,mode:"read_only_main_ui_selected_slate_no_cron_no_scheduled_jobs_no_writes",source_table:loaded.source_table,rows_count:hydrated.length,prop_families_active:ACTIVE_PROP_FAMILIES,prop_counts:propCounts,line_type_counts:typeCounts,rows:hydrated,note:"Independent AlphaDog main UI worker. Reads D1 only. Does not run scoring, cron, scheduled tasks, external APIs, Gemini, or database writes. Root worker serves HTML directly; no Workers Assets scan is used."})}

async function firstOrNull(db, sql, ...binds){try{let st=db.prepare(sql); if(binds.length) st=st.bind(...binds); return await st.first()}catch(e){return null}}
async function countOrZero(db, sql, ...binds){const r=await firstOrNull(db, sql, ...binds); return Number(Object.values(r||{})[0]||0)}
async function latestValue(db, sql, ...binds){const r=await firstOrNull(db, sql, ...binds); return Object.values(r||{})[0]||null}
function quality(base, penalties){let q=Number(base||100); for(const p of penalties||[]) q-=Number(p||0); return Math.max(0,Math.min(100,Math.round(q)))}
function nextText(kind){const map={static:"Weekly scheduled refresh",incremental_base:"Safe base; no regular refresh",incremental_daily:"Daily scheduler / next minute continuation",everyday:"Daily slate schedule",odds:"4:30 AM, 6:00 AM, 11:00 AM PT windows",prizepicks:"GitHub scrape schedule: 5A/8A/11A/2P/5P/11P PT",sleeper:"Manual only"};return map[kind]||"By schedule"}
async function adminStatus(request,env){if(!env.DB)return jsonResponse({ok:false,error:"Missing DB binding named DB"},500);const db=env.DB;const latestTask=async(jobs)=>await firstOrNull(db,`SELECT job_name,status,finished_at,started_at,error FROM task_runs WHERE job_name IN (${jobs.map(()=>'?').join(',')}) ORDER BY COALESCE(finished_at,started_at) DESC LIMIT 1`,...jobs);const card=[];
const staticRows=(await countOrZero(db,"SELECT COUNT(*) AS c FROM ref_venues"))+(await countOrZero(db,"SELECT COUNT(*) AS c FROM ref_players"))+(await countOrZero(db,"SELECT COUNT(*) AS c FROM ref_team_aliases"));const staticLast=await latestValue(db,"SELECT MAX(updated_at) AS m FROM ref_players");card.push({title:"Static Data",frequency:"Weekly",last_update:staticLast,ok:staticRows>100,quality_score:quality(99,[staticRows<100?25:0,!staticLast?20:0]),quality_note:staticRows>100?"Reference tables present; weekly refresh is only a safeguard.":"Reference coverage is low or missing.",next_update:nextText('static')});
const incRows=(await countOrZero(db,"SELECT COUNT(*) AS c FROM player_game_logs"))+(await countOrZero(db,"SELECT COUNT(*) AS c FROM ref_player_splits"));const incLast=await latestValue(db,"SELECT MAX(updated_at) AS m FROM player_game_logs");card.push({title:"Incremental Base",frequency:"Safe base",last_update:incLast,ok:incRows>100,quality_score:quality(98,[incRows<100?25:0]),quality_note:"Base persists; only certified-A increments should extend it.",next_update:nextText('incremental_base')});
const incDaily=await latestTask(['run_incremental_temp_refresh_tick','schedule_incremental_temp_refresh_once','incremental_base_game_logs_g1','incremental_base_game_logs_g2','incremental_base_game_logs_g3','incremental_base_player_splits_g1','incremental_base_derived_metrics']);card.push({title:"Incremental Daily",frequency:"Daily",last_update:incDaily?.finished_at||incDaily?.started_at,ok:!incDaily||String(incDaily.status).includes('success')||String(incDaily.status).includes('complete'),quality_score:quality(94,[incDaily&&String(incDaily.status).includes('fail')?30:0]),quality_note:incDaily?`Latest job: ${incDaily.job_name} / ${incDaily.status}`:"No recent incremental job found.",next_update:nextText('incremental_daily')});
const games=await countOrZero(db,"SELECT COUNT(*) AS c FROM games WHERE game_date=(SELECT MAX(game_date) FROM games)");const everydayLast=await latestValue(db,"SELECT MAX(updated_at) AS m FROM games");card.push({title:"Everyday Data",frequency:"Daily replace",last_update:everydayLast,ok:games>0,quality_score:quality(96,[games<=0?35:0]),quality_note:`Latest slate games: ${games}. Daily slate data should be replaced, not treated as permanent.`,next_update:nextText('everyday')});
const oddsRows=await countOrZero(db,"SELECT COUNT(*) AS c FROM odds_api_player_props WHERE slate_date=(SELECT MAX(slate_date) FROM odds_api_player_props)");const oddsLast=await latestValue(db,"SELECT MAX(updated_at) AS m FROM odds_api_player_props");card.push({title:"Market/Odds",frequency:"Intraday",last_update:oddsLast,ok:oddsRows>0,quality_score:quality(96,[oddsRows<=0?40:0]),quality_note:`Latest odds prop rows: ${oddsRows}. Freshness is audit-only in scoring V1.`,next_update:nextText('odds')});
const ppRows=await countOrZero(db,"SELECT COUNT(*) AS c FROM prizepicks_current_market_context WHERE status='ACTIVE'");const ppLast=await latestValue(db,"SELECT MAX(board_updated_at) AS m FROM prizepicks_current_market_context WHERE status='ACTIVE'");card.push({title:"PrizePicks Board",frequency:"Auto scrape",last_update:ppLast,ok:ppRows>0,quality_score:quality(97,[ppRows<=0?45:0]),quality_note:`Active board rows: ${ppRows}. Old superseded rows may remain for audit, but release uses active/pickable rows.`,next_update:nextText('prizepicks')});
const slRows=await countOrZero(db,"SELECT COUNT(*) AS c FROM sleeper_rbi_rfi_market_signals WHERE signal_status='CERTIFIED_BOARD_PRESENT'");const slLast=await latestValue(db,"SELECT MAX(updated_at) AS m FROM sleeper_rbi_rfi_market_signals");card.push({title:"Sleeper Board",frequency:"Manual",last_update:slLast,ok:slRows>=0,quality_score:quality(slRows>0?92:78,[]),quality_note:slRows>0?`Certified manual board rows: ${slRows}. Started or <15 minute legs are treated non-existent.`:"No certified manual Sleeper rows currently visible.",next_update:nextText('sleeper')});
return jsonResponse({ok:true,version:MAIN_ALPHADOG_UI_VERSION,cards:card});}
async function adminRefresh(request,env){const body=await request.json().catch(()=>({}));if(String(body.pin||'')!=="3971")return jsonResponse({ok:false,error:"Wrong PIN"},401);const base=String(env.CONTROL_WORKER_URL||"https://prop-ingestion-git.rodolfoaamattos.workers.dev").replace(/\/$/,"");const token=env.CONTROL_WORKER_INGEST_TOKEN||env.INGEST_TOKEN;if(!token)return jsonResponse({ok:false,error:"Missing CONTROL_WORKER_INGEST_TOKEN or INGEST_TOKEN secret on main UI worker"},500);const r=await fetch(base+"/main-ui/admin-refresh/start",{method:"POST",headers:{"content-type":"application/json","x-ingest-token":token},body:JSON.stringify({source:"main_ui_admin",pin_screen_only:true})});const j=await r.json().catch(()=>({ok:false,error:"control_worker_non_json"}));return jsonResponse({...j,proxied_to:base},r.ok?200:500)}

export default{async fetch(request,env){const url=new URL(request.url);if(request.method==="OPTIONS")return new Response(null,{headers:{"access-control-allow-origin":"*","access-control-allow-methods":"GET, POST, OPTIONS","access-control-allow-headers":"content-type"}});if(url.pathname==="/"||url.pathname==="/index.html")return htmlResponse(INDEX_HTML);if(["/main_alphadog_logo.png","/main_alphadog_favicon.png","/main_alphadog_apple_touch_icon.png"].includes(url.pathname))return pngResponse();if(url.pathname==="/main_alphadog_health")return jsonResponse({ok:true,version:MAIN_ALPHADOG_UI_VERSION,worker:"main_alphadog_worker",db_bound:Boolean(env.DB),control_url_bound:Boolean(env.CONTROL_WORKER_URL),ingest_token_bound:Boolean(env.INGEST_TOKEN||env.CONTROL_WORKER_INGEST_TOKEN),assets_required:false});if(url.pathname==="/main_alphadog_board"||url.pathname==="/ui/board")return board(request,env);if(url.pathname==="/main_alphadog_admin_status")return adminStatus(request,env);if(url.pathname==="/main_alphadog_admin_refresh"&&request.method==="POST")return adminRefresh(request,env);return textResponse("AlphaDog main UI route not found",404)}};